		pBufRaw []byte
		encBuf  = compression.NewSyncEncodeBuffer()
	)
	// TODO(@tpaschalis) Should we also raise the max if we have WAL metadata?
	if s.qm.sendExemplars {
		maxCount += int(float64(maxCount) * 0.1)
	}

