		n := nPendingSamples + nPendingExemplars + nPendingHistograms
		if nUnexpectedMetadata > 0 {
			s.qm.logger.Warn("unexpected metadata sType in populateV2TimeSeries", "count", nUnexpectedMetadata)
		}

